SELECT vendor_id, AVG(rating) AS average_rating
FROM vendor_ratings
GROUP BY vendor_id;

SELECT MAX(appointment_required) AS max_appointment_required
FROM vendor_services
WHERE service_name = 'Electronics Recycling';

SELECT MAX(quantity_limit) AS max_quantity_limit
FROM items_accepted
WHERE electronic_id = 1;

SELECT facility_name
FROM vendor_facilities
WHERE status = 'operational';

SELECT vendor_id, rating
FROM vendor_ratings
WHERE service_type = 'recycling';

SELECT COUNT(*) AS operational_facilities
FROM vendor_facilities
WHERE status = 'operational';

SELECT COUNT(DISTINCT vendor_id) AS total_vendors_with_pickup_services
FROM pickup_services
WHERE pickup_available = 'YES';

SELECT COUNT(*) AS active_employee_count
FROM vendor_employees
WHERE vendor_id = 1 AND status = 'active';

SELECT COUNT(vendor_id) AS number_of_vendors
FROM pickup_services
WHERE pickup_available = 'Yes';

SELECT AVG(rating) AS average_rating
FROM vendor_ratings
WHERE vendor_id = 0;

SELECT COUNT(*) AS valid_cert_count
FROM vendor_certifications
WHERE certification_status = 'valid';

SELECT certification_name
FROM vendor_certifications
WHERE certification_status = 'valid';

SELECT vendor_id, electronic_id, condition_accepted, recycling_fees
FROM items_accepted
WHERE vendor_id = 0;
